#!/usr/bin/env python3
from pwn import remote, context
import time, os, subprocess, random, string

HOST='crypto.chal.csaw.io'
PORT=8000
context.log_level='error'

def recv_burst(r, total_wait=1.5, chunk_timeout=0.25):
    out=b''
    end=time.time()+total_wait
    while time.time()<end:
        try:
            b=r.recv(timeout=chunk_timeout)
            if b:
                out += b
                # allow trailing chunks
                end=min(end, time.time()+0.3)
            else:
                break
        except EOFError:
            return out, True, 'EOFError'
        except Exception as e:
            return out, False, f'err:{e}'
    return out, False, 'timeout/idle'

def attempt_with_payload(name, payload, prewait=0.0):
    res={"name":name}
    try:
        r=remote(HOST,PORT)
    except Exception as e:
        res['connect_error']=str(e)
        return res

    if prewait:
        time.sleep(prewait)

    init, closed_init, reason_init = recv_burst(r, total_wait=3.0 if prewait else 1.5)
    res['init']=init
    res['init_closed']=closed_init
    res['init_reason']=reason_init

    if payload is not None:
        try:
            if isinstance(payload, list):
                for p in payload:
                    r.send(p)
                    time.sleep(0.15)
            else:
                r.send(payload)
            res['send_ok']=True
        except Exception as e:
            res['send_ok']=False
            res['send_error']=str(e)

        post, closed_post, reason_post = recv_burst(r, total_wait=1.8)
        res['post']=post
        res['post_closed']=closed_post
        res['post_reason']=reason_post

    try:
        r.close()
    except:
        pass
    return res

def pretty_bytes(b):
    if b is None:
        return 'None'
    s=b.decode('utf-8','replace')
    return repr(s)

def run_pwntools_tests():
    tests=[
        ('empty_line', b'\n'),
        ('single_A', b'A\n'),
        ('hex_string', b'deadbeefcafebabe\n'),
        ('long_random', (''.join(random.choice(string.ascii_letters+string.digits) for _ in range(1024))+'\n').encode()),
        ('multiple_lines', [b'first\n', b'second\n', b'third\n']),
    ]

    outputs=[]
    # hidden menu timing check
    outputs.append(attempt_with_payload('timing_only_wait3_no_send', None, prewait=3.0))
    for n,p in tests:
        outputs.append(attempt_with_payload(n,p,prewait=0.0))
    return outputs

def run_nc_style(payload=b'A\n', wait_before_send=0.0):
    # emulate netcat interaction using subprocess and stdin/stdout pipes
    cmd=['nc', HOST, str(PORT)]
    p=subprocess.Popen(cmd, stdin=subprocess.PIPE, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    transcript={}
    try:
        time.sleep(wait_before_send)
        # collect initial output if any
        time.sleep(0.8)
        init=b''
        try:
            init=os.read(p.stdout.fileno(), 4096)
        except BlockingIOError:
            init=b''
        except Exception:
            init=b''

        if payload is not None:
            p.stdin.write(payload)
            p.stdin.flush()
        time.sleep(1.0)
        post=b''
        try:
            post=os.read(p.stdout.fileno(), 4096)
        except Exception:
            post=b''

        transcript['init']=init
        transcript['post']=post
        p.terminate()
        try:
            p.wait(timeout=1)
        except:
            p.kill()
    except Exception as e:
        transcript['error']=str(e)
        try:
            p.kill()
        except:
            pass
    return transcript

if __name__=='__main__':
    print('=== PWNTOOLS PROTOCOL FUZZ ===')
    out=run_pwntools_tests()
    for i,r in enumerate(out,1):
        print(f"\n--- Attempt {i}: {r.get('name')} ---")
        if 'connect_error' in r:
            print('connect_error:',r['connect_error'])
            continue
        print('init:', pretty_bytes(r.get('init',b'')))
        print('init_closed:', r.get('init_closed'), 'init_reason:', r.get('init_reason'))
        if 'send_ok' in r:
            print('send_ok:', r.get('send_ok'), 'send_error:', r.get('send_error'))
            print('post:', pretty_bytes(r.get('post',b'')))
            print('post_closed:', r.get('post_closed'), 'post_reason:', r.get('post_reason'))

    print('\n=== NC-STYLE CHECKS ===')
    # simple nc style with A and multi-line
    t1=run_nc_style(b'A\n',0.0)
    print('\n[NC attempt 1 A] init=',pretty_bytes(t1.get('init',b'')),' post=',pretty_bytes(t1.get('post',b'')),' err=',t1.get('error'))
    t2=run_nc_style(b'first\nsecond\nthird\n',0.0)
    print('[NC attempt 2 multiline] init=',pretty_bytes(t2.get('init',b'')),' post=',pretty_bytes(t2.get('post',b'')),' err=',t2.get('error'))
    t3=run_nc_style(None,3.0)
    print('[NC attempt 3 wait3_no_send] init=',pretty_bytes(t3.get('init',b'')),' post=',pretty_bytes(t3.get('post',b'')),' err=',t3.get('error'))

