        res['post']=post
        res['post_closed']=closed_post
        res['post_reason']=reason_post

    try:
        r.close()
    except:
        pass
    return res

def pretty_bytes(b):
    if b is None:
        return 'None'
    return repr(b.decode('utf-8','replace'))

def run_pwntools_tests():
    tests=[
        ('empty_line', b'\n'),
        ('single_A', b'A\n'),
        ('hex_string', b'deadbeefcafebabe\n'),
        ('long_random', (''.join(random.choice(string.ascii_letters+string.digits) for _ in range(1024))+'\n').encode()),
        ('multiple_lines', [b'first\n', b'second\n', b'third\n']),
    ]
    outputs=[attempt_with_payload('timing_only_wait3_no_send', None, prewait=3.0)]
    for n,p in tests:
