def read_available(fd, timeout=1.0):
    out=b''
    end=time.time()+timeout
    while time.time()<end:
        r,_,_=select.select([fd],[],[],0.2)
        if not r:
            continue
        chunk=os.read(fd, 4096)
        if not chunk:
            break
        out += chunk
    return out

