        if wait_before_send:
            time.sleep(wait_before_send)
        init=read_available(fd, timeout=1.2)

        if payload is not None:
            p.stdin.write(payload)
            p.stdin.flush()
        post=read_available(fd, timeout=1.5)

        transcript['init']=init
        transcript['post']=post
    except Exception as e:
        transcript['error']=str(e)
    finally:
        try: p.terminate()
        except: pass
        try: p.wait(timeout=1)
        except:
            try: p.kill()
            except: pass
    return transcript

