    out=run_pwntools_tests()
    for i,r in enumerate(out,1):
        print(f"\n--- Attempt {i}: {r.get('name')} ---")
        if 'connect_error' in r:
            print('connect_error:',r['connect_error'])
            continue
        print('init:', pretty_bytes(r.get('init',b'')))
        print('init_closed:', r.get('init_closed'), 'init_reason:', r.get('init_reason'))
        if 'send_ok' in r:
            print('send_ok:', r.get('send_ok'), 'send_error:', r.get('send_error'))
            print('post:', pretty_bytes(r.get('post',b'')))
            print('post_closed:', r.get('post_closed'), 'post_reason:', r.get('post_reason'))

    print('\n=== NC-STYLE CHECKS ===')
    t1=run_nc_style(b'A\n',0.0)
    print('[NC attempt 1 A] init=',pretty_bytes(t1.get('init',b'')),' post=',pretty_bytes(t1.get('post',b'')),' err=',t1.get('error'))
    t2=run_nc_style(b'first\nsecond\nthird\n',0.0)
    print('[NC attempt 2 multiline] init=',pretty_bytes(t2.get('init',b'')),' post=',pretty_bytes(t2.get('post',b'')),' err=',t2.get('error'))
    t3=run_nc_style(None,3.0)
    print('[NC attempt 3 wait3_no_send] init=',pretty_bytes(t3.get('init',b'')),' post=',pretty_bytes(t3.get('post',b'')),' err=',t3.get('error'))

#!/usr/bin/env python3
from pwn import *
import re
context.log_level='error'
HOST,PORT='crypto.chal.csaw.io',8000
BS=16

class Oracle:
    def __init__(self):
        self.io=remote(HOST,PORT)
        self.init_hex=self.io.recvline().strip().decode()
    def q(self,m:bytes)->bytes:
        self.io.sendline(m)
        self.io.recvline() # echo
        return bytes.fromhex(self.io.recvline().strip().decode())
    def close(self): self.io.close()

def recover_once(max_bytes=128):
    o=Oracle()
    base_len=len(o.q(b''))
    # find secret+padded total length baseline
    recovered=b''
    for i in range(max_bytes):
        pad=BS-1-(len(recovered)%BS)
        prefix=b'A'*pad
        ref=o.q(prefix)
        bi=len(recovered)//BS
        target=ref[bi*BS:(bi+1)*BS]
        d={}
        known=(prefix+recovered)[-(BS-1):]
        for g in range(256):
            c=o.q(known+bytes([g]))
            d[c[bi*BS:(bi+1)*BS]]=g
        if target in d:
            recovered+=bytes([d[target]])
        else:
            break
    o.close()
    return recovered

def main():
    for s in range(6):
        rec=recover_once(96)
        print(f'[*] session {s} recovered {len(rec)} bytes: {rec!r}')
        m=re.search(rb'flag\{[^}]+\}',rec)
        if m:
            print('[+] FLAG',m.group(0).decode())
            return
    print('[-] no flag regex found')

if __name__=='__main__':
    main()

#!/usr/bin/env python3
from pwn import *
import re

context.log_level = 'error'
HOST, PORT = 'crypto.chal.csaw.io', 8000
BS = 16

class Oracle:
    def __init__(self, timeout=1.5):
        self.io = remote(HOST, PORT, timeout=timeout)
        # banner line appears to be hex string; not needed
        self.init_hex = self.io.recvline(timeout=timeout)

    def q(self, msg: bytes) -> bytes:
        self.io.sendline(msg)
        # server echoes input then ciphertext hex line
        self.io.recvline(timeout=1.5)
        out = self.io.recvline(timeout=1.5)
        if not out:
            raise EOFError('no ciphertext line')
        return bytes.fromhex(out.strip().decode())

    def close(self):
        try:
            self.io.close()
        except Exception:
            pass


def infer_secret_len(o: Oracle):
    base_ct_len = len(o.q(b''))
    # find first n where ciphertext length increases by one block
    n = 1
    while n < BS * 4:
        l = len(o.q(b'A' * n))
        if l > base_ct_len:
            first_inc = n
            break
        n += 1
    else:
        raise RuntimeError('Could not infer secret length increment')

    # Let S be secret len. base_ct_len = BS * ceil(S/BS)
    # first_inc = minimal n where ceil((S+n)/BS) > ceil(S/BS)
    # => first_inc = BS - (S mod BS), except when S mod BS == 0 then first_inc=BS
    rem = BS - first_inc
    if rem == BS:
        rem = 0
    secret_len = base_ct_len - (BS - rem if rem != 0 else 0)
    return secret_len, base_ct_len, first_inc


def recover_session(max_total=256):
    o = Oracle()
    recovered = b''
    try:
        secret_len, base_ct_len, first_inc = infer_secret_len(o)

        # recover bytes; stop when flag{...} found
        for _ in range(min(secret_len, max_total)):
            pad = BS - 1 - (len(recovered) % BS)
            prefix = b'A' * pad

            ref = o.q(prefix)
            bi = len(recovered) // BS
            tgt = ref[bi*BS:(bi+1)*BS]

            known = (prefix + recovered)[-(BS-1):]
            d = {}
            for g in range(256):
                c = o.q(known + bytes([g]))
                d[c[bi*BS:(bi+1)*BS]] = g

            if tgt not in d:
                break
            recovered += bytes([d[tgt]])

            m = re.search(rb'flag\{[^}]*\}', recovered)
            if m:
                return recovered, m.group(0), (secret_len, base_ct_len, first_inc)

        m = re.search(rb'flag\{[^}]*\}', recovered)
        return recovered, (m.group(0) if m else None), (secret_len, base_ct_len, first_inc)
    finally:
        o.close()


def partial_confirm(prefix_len):
    # re-run only enough recovery to confirm same flag text appears
    rec, m, meta = recover_session(max_total=prefix_len)
    return rec, m, meta


def main():
    # retry full session if desync/network hiccup
    flag = None
    first_rec = b''
    first_meta = None
    for attempt in range(6):
        try:
            rec, m, meta = recover_session(max_total=192)
            first_rec, first_meta = rec, meta
            print(f'[*] attempt {attempt}: inferred secret_len={meta[0]}, base_ct_len={meta[1]}, first_inc={meta[2]}, recovered={len(rec)}')
            if m:
                flag = m
                print(f'[+] candidate {flag.decode()}')
                break
        except Exception as e:
            print(f'[!] attempt {attempt} failed: {e}')

    if not flag:
        # regex-scan whatever we got
        m = re.search(rb'flag\{[^}]+\}', first_rec)
        if m:
            flag = m.group(0)

    if flag:
        # validation in a fresh reconnect
        need = len(flag)
        ok = False
        for j in range(4):
            try:
                rec2, m2, meta2 = partial_confirm(need + 8)
                print(f'[*] confirm {j}: inferred secret_len={meta2[0]}, recovered={len(rec2)}')
                if flag in rec2 or (m2 and m2 == flag):
                    ok = True
                    break
            except Exception as e:
                print(f'[!] confirm {j} failed: {e}')
        print(f'[+] FLAG {flag.decode()}')
        print(f'[+] validation={ok}')
    else:
        print('[-] no flag found')

if __name__ == '__main__':
    main()

