#!/usr/bin/env python3
from pwn import *
import re

context.log_level = 'error'
HOST, PORT = 'crypto.chal.csaw.io', 8000
BS = 16
PROMPT = b'Tell me something: '
HEX_RE = re.compile(rb'([0-9a-fA-F]{32,})')

class Oracle:
    def __init__(self, timeout=2.0):
        self.io = remote(HOST, PORT, timeout=timeout)
        self.timeout = timeout
        self.buf = b''
        # sync to first prompt
        self._recv_to_prompt()

    def _recv_to_prompt(self):
        chunk = self.io.recvuntil(PROMPT, timeout=self.timeout)
        if not chunk.endswith(PROMPT):
            raise EOFError('desync/no prompt')
        self.buf = chunk[:-len(PROMPT)]
        return self.buf

    def _parse_last_hex(self, data: bytes) -> bytes:
        ms = HEX_RE.findall(data)
        if not ms:
            raise ValueError(f'no hex line in {data[-120:]!r}')
        return bytes.fromhex(ms[-1].decode())

    def q(self, msg: bytes) -> bytes:
        self.io.sendline(msg)
        data = self._recv_to_prompt()
        return self._parse_last_hex(data)

    def close(self):
        try:
            self.io.close()
        except Exception:
            pass


def infer_secret_len(o: Oracle):
    base_ct_len = len(o.q(b''))
    first_inc = None
    for n in range(1, BS * 3 + 1):
        if len(o.q(b'A' * n)) > base_ct_len:
            first_inc = n
            break
    if first_inc is None:
        raise RuntimeError('increment not found')

    # pad needed to next block for empty input
    pad_to_next = first_inc if first_inc < BS else 0
    secret_len = base_ct_len - pad_to_next
    return secret_len, base_ct_len, first_inc


def recover_session(max_total=256):
    o = Oracle()
    recovered = b''
    try:
        secret_len, base_ct_len, first_inc = infer_secret_len(o)
        limit = min(secret_len, max_total)

        for _ in range(limit):
            pad = BS - 1 - (len(recovered) % BS)
            prefix = b'A' * pad
            ref = o.q(prefix)
            bi = len(recovered) // BS
            tgt = ref[bi*BS:(bi+1)*BS]

            known = (prefix + recovered)[-(BS-1):]
            table = {}
            for g in range(256):
                c = o.q(known + bytes([g]))
                table[c[bi*BS:(bi+1)*BS]] = g

            if tgt not in table:
                break
            recovered += bytes([table[tgt]])

            m = re.search(rb'flag\{[^}]*\}', recovered)
            if m:
                return recovered, m.group(0), (secret_len, base_ct_len, first_inc)

        m = re.search(rb'flag\{[^}]+\}', recovered)
        return recovered, (m.group(0) if m else None), (secret_len, base_ct_len, first_inc)
    finally:
        o.close()


def main():
    cand = None
    first_rec = b''
    first_meta = None

    for a in range(8):
        try:
            rec, m, meta = recover_session(max_total=192)
            first_rec, first_meta = rec, meta
            print(f'[*] attempt {a}: secret_len={meta[0]} base_ct={meta[1]} inc={meta[2]} recovered={len(rec)}')
            if m:
                cand = m
                print(f'[+] candidate: {cand.decode(errors="ignore")}')
                break
        except Exception as e:
            print(f'[!] attempt {a} failed: {e}')

    if cand is None:
        m = re.search(rb'flag\{[^}]+\}', first_rec)
        if m:
            cand = m.group(0)

    if cand is None:
        print('[-] no flag found')
        return

    # confirm via fresh sessions with partial recovery only
    need = len(cand) + 4
    ok = False
    for j in range(4):
        try:
            rec2, m2, meta2 = recover_session(max_total=need)
            print(f'[*] confirm {j}: secret_len={meta2[0]} recovered={len(rec2)}')
            if cand in rec2 or (m2 and m2 == cand):
                ok = True
                break
        except Exception as e:
            print(f'[!] confirm {j} failed: {e}')

    print(f'[+] FLAG {cand.decode()}')
    print(f'[+] validation={ok}')

if __name__ == '__main__':
    main()

