#!/usr/bin/env python3
from pwn import *
import re

context.log_level = 'error'
HOST, PORT = 'crypto.chal.csaw.io', 8000
BS = 16
PROMPT = b'Tell me something: '
FLAG_RE = re.compile(rb'flag\{[^}]+\}')

class Oracle:
    def __init__(self, timeout=2.0):
        self.io = remote(HOST, PORT, timeout=timeout)
        # Server sends: first ciphertext line + prompt
        self.init_ct = self.io.recvline(timeout=timeout).strip()
        self._sync_to_prompt(timeout)

    def _sync_to_prompt(self, timeout=2.0):
        self.io.recvuntil(PROMPT, timeout=timeout)

    def q(self, m: bytes) -> bytes:
        self.io.sendline(m)
        # response: echo line, ciphertext line, prompt
        _ = self.io.recvline(timeout=2.0)
        cthex = self.io.recvline(timeout=2.0).strip()
        self._sync_to_prompt(2.0)
        return bytes.fromhex(cthex.decode())

    def close(self):
        try:
            self.io.close()
        except Exception:
            pass

def infer_secret_len(o: Oracle):
    base_ct_len = len(o.q(b''))
    n = 1
    while True:
        l = len(o.q(b'A' * n))
        if l > base_ct_len:
            # first increment at n where crossing padding boundary
            pad_to_next = n
            break
        n += 1
        if n > BS * 4:
            raise RuntimeError('Could not infer length increment')
    # total plaintext length before PKCS#7 pad (input='' case)
    total_plain_len = base_ct_len - pad_to_next
    return total_plain_len, base_ct_len, pad_to_next


def recover_flag_once(max_total=256):
    o = Oracle(timeout=2.0)
    try:
        total_plain_len, base_ct_len, pad_to_next = infer_secret_len(o)
        recovered = b''
        # Only need until first flag close brace appears
        limit = min(total_plain_len, max_total)

        for _ in range(limit):
            pad = BS - 1 - (len(recovered) % BS)
            prefix = b'A' * pad

            ref = o.q(prefix)
            bi = len(recovered) // BS
            target = ref[bi*BS:(bi+1)*BS]

            known = (prefix + recovered)[-(BS-1):]
            d = {}
            for g in range(256):
                c = o.q(known + bytes([g]))
                d[c[bi*BS:(bi+1)*BS]] = g

            if target not in d:
                break
            recovered += bytes([d[target]])

            # stop early once flag{...} complete
            m = FLAG_RE.search(recovered)
            if m:
                return recovered, m.group(0), (total_plain_len, base_ct_len, pad_to_next)

        m = FLAG_RE.search(recovered)
        return recovered, (m.group(0) if m else None), (total_plain_len, base_ct_len, pad_to_next)
    finally:
        o.close()


def recover_with_retries(retries=6):
    best = None
    for i in range(retries):
        try:
            rec, flag, meta = recover_flag_once()
            if best is None or len(rec) > len(best[0]):
                best = (rec, flag, meta)
            if flag:
                return rec, flag, meta, i+1
        except Exception:
            continue
    if best:
        return best[0], best[1], best[2], retries
    return b'', None, None, retries


def confirm_flag(flag_bytes: bytes):
    # Re-run partial recovery and ensure same flag appears again
    rec2, flag2, _, _ = recover_with_retries(retries=4)
    if flag2 and flag2 == flag_bytes:
        return True, rec2, flag2
    # fallback: regex scan if exact match not isolated first time
    m2 = FLAG_RE.search(rec2)
    if m2 and m2.group(0) == flag_bytes:
        return True, rec2, m2.group(0)
    return False, rec2, flag2


def main():
    rec, flag, meta, tries = recover_with_retries(retries=8)
    print(f'[*] tries used: {tries}')
    if meta:
        tlen, clen, inc = meta
        print(f'[*] inferred total_plain_len(secret)={tlen}, base_ct_len={clen}, first_inc_at_input_len={inc}')
    print(f'[*] recovered_prefix_len={len(rec)}')
    print(f'[*] recovered_prefix={rec!r}')

    m = FLAG_RE.search(rec)
    if flag is None and m:
        flag = m.group(0)

    if flag:
        ok, rec2, flag2 = confirm_flag(flag)
        print(f'[*] confirmation_ok={ok}')
        print(f'[*] second_recovery_prefix_len={len(rec2)}')
        print(f'[*] second_recovery_prefix={rec2!r}')
        print(f'[+] FLAG: {flag.decode()}')
    else:
        print('[-] Flag not found')

if __name__ == '__main__':
    main()

