    base = len(o.q(b''))
    inc_at = None
    for n in range(1, BS * 3 + 1):
        ln = len(o.q(b'A' * n))
        if ln > base:
            inc_at = n
            break
    if inc_at is None:
        raise RuntimeError('Could not find block-length increase point')
    # base = ceil(secret_len/BS)*BS, and inc_at = padding_len+1
    pad_len = inc_at - 1
    secret_len = base - pad_len
    return secret_len, base, inc_at


