#!/usr/bin/env python3
from pwn import *
import re

context.log_level = 'error'
HOST, PORT = 'crypto.chal.csaw.io', 8000
BS = 16
FLAG_RE = re.compile(rb'flag\{[^}]+\}')

class Oracle:
    def __init__(self, timeout=2):
        self.io = remote(HOST, PORT, timeout=timeout)
        self.banner = self.io.recvline(timeout=timeout).strip()

    def q(self, msg: bytes) -> bytes:
        self.io.sendline(msg)
        echo = self.io.recvline(timeout=2)
        ct = self.io.recvline(timeout=2)
        if not ct:
            raise EOFError('no ciphertext line')
        return bytes.fromhex(ct.strip().decode())

    def close(self):
        try:
            self.io.close()
        except Exception:
            pass


def infer_secret_len(o: Oracle):
    base = len(o.q(b''))
    jump_n = None
    for n in range(1, BS * 3 + 1):
        l = len(o.q(b'A' * n))
        if l > base:
            jump_n = n
            break
    if jump_n is None:
        raise RuntimeError('failed to detect length jump')
    # PKCS#7 padded: jump at n = pad+1, where pad = BS - (secret_len % BS)
    pad = jump_n - 1
    secret_mod = (BS - pad) % BS
    # Since base is padded length of secret, minimal candidate:
    secret_len = base - (BS if secret_mod == 0 else (BS - secret_mod))
    if secret_len < 0:
        secret_len = 0
    return base, secret_len, jump_n


def recover_until_flag(o: Oracle, max_bytes=256):
    recovered = b''
    for i in range(max_bytes):
        pad_len = BS - 1 - (len(recovered) % BS)
        prefix = b'A' * pad_len

        ref = o.q(prefix)
        block_idx = len(recovered) // BS
        target = ref[block_idx * BS:(block_idx + 1) * BS]

        known_tail = (prefix + recovered)[-(BS - 1):]
        d = {}
        for g in range(256):
            c = o.q(known_tail + bytes([g]))
            d[c[block_idx * BS:(block_idx + 1) * BS]] = g

        if target not in d:
            break
        recovered += bytes([d[target]])

        if b'flag{' in recovered and b'}' in recovered[recovered.find(b'flag{'):]:
            break
    return recovered


def recover_session(max_bytes=256):
    o = Oracle()
    try:
        base, sec_len, jump = infer_secret_len(o)
        rec = recover_until_flag(o, max_bytes=max_bytes)
        return {
            'banner': o.banner,
            'base_ct_len': base,
            'secret_len_est': sec_len,
            'jump_at': jump,
            'recovered': rec,
        }
    finally:
        o.close()


def main():
    # retry sessions if desync / unstable
    best = None
    for _ in range(4):
        try:
            res = recover_session(192)
            best = res
            m = FLAG_RE.search(res['recovered'])
            print(f"[*] recovered {len(res['recovered'])} bytes")
            print(f"[*] base_ct={res['base_ct_len']} jump_at={res['jump_at']} secret_len_est={res['secret_len_est']}")
            print(res['recovered'])
            if m:
                flag = m.group(0)
