from pwn import *
import re

context.log_level = 'error'
HOST, PORT = 'crypto.chal.csaw.io', 8000
BS = 16
FLAG_RE = re.compile(rb'flag\{[^}]+\}')
HEX_RE = re.compile(rb'([0-9a-fA-F]{32,})')

class Oracle:
    def __init__(self, timeout=2):
        self.io = remote(HOST, PORT, timeout=timeout)
        self.timeout = timeout
        self.first_ct = self._recv_ct_line()

    def _recv_ct_line(self) -> bytes:
        # read lines until one contains long hex blob
        for _ in range(8):
            l = self.io.recvline(timeout=self.timeout)
            if not l:
                continue
            m = HEX_RE.search(l.strip())
            if m:
                return bytes.fromhex(m.group(1).decode())
        raise EOFError('no ciphertext line found')

    def q(self, msg: bytes) -> bytes:
        self.io.sendline(msg)
        return self._recv_ct_line()

    def close(self):
        try:
            self.io.close()
        except Exception:
            pass


def infer_secret_len(o: Oracle):
    base = len(o.q(b''))
    jump_n = None
    for n in range(1, BS * 4 + 1):
        if len(o.q(b'A' * n)) > base:
            jump_n = n
            break
    if jump_n is None:
        raise RuntimeError('failed to detect ciphertext length jump')
    # base = padded(secret_len)
    # jump at n where n > pad, pad = BS - (secret_len mod BS), or 0 if mod 0 then BS
    pad = jump_n - 1
    secret_len = base - pad
    return base, secret_len, jump_n


def recover_until_flag(o: Oracle, max_bytes=256):
    recovered = b''
    for _ in range(max_bytes):
        pad_len = BS - 1 - (len(recovered) % BS)
        prefix = b'A' * pad_len
        ref = o.q(prefix)

        block_idx = len(recovered) // BS
        target = ref[block_idx * BS:(block_idx + 1) * BS]

        known_tail = (prefix + recovered)[-(BS - 1):]
        table = {}
        for g in range(256):
            c = o.q(known_tail + bytes([g]))
            table[c[block_idx * BS:(block_idx + 1) * BS]] = g

        v = table.get(target)
        if v is None:
            break
        recovered += bytes([v])

        m = FLAG_RE.search(recovered)
        if m:
            return recovered
        if b'flag{' in recovered and b'}' in recovered[recovered.find(b'flag{'):]:
            return recovered
    return recovered


def recover_session(max_bytes=192):
    o = Oracle(timeout=2)
    try:
        base, sec_len, jump = infer_secret_len(o)
        rec = recover_until_flag(o, max_bytes=max_bytes)
        return base, sec_len, jump, rec
    finally:
        o.close()


def main():
    candidate = None
    for _ in range(5):
        try:
            base, sec_len, jump, rec = recover_session()
            print(f"[*] base_ct={base} jump_at={jump} secret_len_est={sec_len} recovered={len(rec)}")
            print(rec)
            m = FLAG_RE.search(rec)
            if m:
                candidate = m.group(0)
                print('[+] candidate:', candidate.decode())
                break
        except Exception:
            continue

    if not candidate:
        print('[-] no flag recovered')
        return

    # validation
    try:
        _, _, _, rec2 = recover_session()
        m2 = FLAG_RE.search(rec2)
        print(f"[*] validation recovered={len(rec2)}")
        print(rec2)
        if m2 and m2.group(0) == candidate:
            print('[+] confirmed:', candidate.decode())
        else:
            print('[!] validation mismatch; using primary candidate')
    except Exception:
        print('[!] validation failed; using primary candidate')


if __name__ == '__main__':
    main()

