FLAG_RE = re.compile(rb'flag\{[^}]+\}')

class Oracle:
    def __init__(self, timeout=0.8):
        self.io = remote(HOST, PORT, timeout=timeout)
        self.timeout = timeout
        self.init = self._read_hex_line()  # initial ciphertext line

    def _read_hex_line(self):
        while True:
            line = self.io.recvline(timeout=self.timeout)
            if not line:
                raise EOFError('no line from server')
            s = line.strip()
            if len(s) % 2 == 0 and HEX_RE.match(s):
                return bytes.fromhex(s.decode())

    def q(self, m: bytes) -> bytes:
        self.io.sendline(m)
        return self._read_hex_line()

    def close(self):
        try:
            self.io.close()
        except Exception:
            pass


def infer_secret_len(o: Oracle):
    base = len(o.q(b''))
    bump_n = None
    for n in range(1, BS + 1):
        l = len(o.q(b'A' * n))
        if l > base:
            bump_n = n
            break
    if bump_n is None:
        bump_n = BS
    # smallest n s.t. length increases => (S mod BS) = BS-(n-1)-1? simplified below
    rem = (BS - bump_n) % BS
    secret_len = base - rem
    if rem == 0:
        # when exactly aligned, bump at n=1, rem=0 and secret_len can be base or base-BS;
        # from PKCS#7 ciphertext includes full block padding, so base is exact padded len of S.
        # S mod BS == 0 => secret_len in {base-BS? no, base already includes +BS padding when aligned}
        # For unknown raw S, true len is base-BS in this aligned case.
        secret_len = base - BS
    return secret_len, base, bump_n


def recover_session(max_recover=256):
    o = Oracle()
    try:
        secret_len, base_len, bump_n = infer_secret_len(o)
        recovered = bytearray()
        target_max = min(secret_len, max_recover)

        for i in range(target_max):
            pad = BS - 1 - (len(recovered) % BS)
            prefix = b'A' * pad
            ref = o.q(prefix)
            bi = len(recovered) // BS
            target = ref[bi*BS:(bi+1)*BS]

            known_tail = (prefix + recovered)[-(BS-1):]
            d = {}
            for g in range(256):
                c = o.q(known_tail + bytes([g]))
                d[c[bi*BS:(bi+1)*BS]] = g

            if target not in d:
                break
            recovered.append(d[target])

            m = FLAG_RE.search(recovered)
            if m:
                return bytes(recovered), m.group(0), (secret_len, base_len, bump_n)

        m = FLAG_RE.search(recovered)
        return bytes(recovered), (m.group(0) if m else None), (secret_len, base_len, bump_n)
    finally:
        o.close()


def main():
    best = None
    found = None
    meta = None

    for attempt in range(1, 6):
        try:
            rec, f, m = recover_session(max_recover=192)
            if best is None or len(rec) > len(best):
                best = rec
                meta = m
            if f:
                found = f
                break
        except Exception:
            continue

    if not found:
        # regex fallback scan on best
        if best:
            mm = FLAG_RE.search(best)
            if mm:
                found = mm.group(0)

    if not found:
        print('[-] flag not found')
        if best is not None:
            print(f'[*] best recovered ({len(best)}): {best!r}')
        return 1

    # validation run: partial re-recovery should include same flag text
    valid = False
    for _ in range(3):
        try:
            rec2, f2, m2 = recover_session(max_recover=192)
            if found in rec2 or f2 == found:
                valid = True
                break
        except Exception:
            pass

    print(f'[+] inferred meta(secret_len,base_ct_len,bump_n): {meta}')
    print(f'[+] recovered flag: {found.decode()}')
    print(f'[+] validation: {valid}')
    return 0

if __name__ == '__main__':
    raise SystemExit(main())

